-- ─────────────────────────────────────────────
-- ADD venue + city columns if not in Phase 1 schema
-- (safe to run even if columns already exist)
-- ─────────────────────────────────────────────
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name='matches' AND column_name='venue'
  ) THEN
    ALTER TABLE matches ADD COLUMN venue text;
    ALTER TABLE matches ADD COLUMN city text;
  END IF;
END
$$;

-- Verify counts
SELECT 'groups' AS table_name, COUNT(*) FROM groups
UNION ALL SELECT 'teams', COUNT(*) FROM teams
UNION ALL SELECT 'matches', COUNT(*) FROM matches;
